// ═══ COLORATION SYNTAXIQUE PYTHON ═══
// ═══ CODE BLOCK ═══
function CodeBlock({ code }) {
  const [copied, setCopied] = useState(false);
  return (
    <div style={{ position:'relative', marginTop:8 }}>
      <pre style={{ background:'#060c18', color:'#e2e8f0', borderRadius:8, padding:'14px 16px',
        fontSize:12, lineHeight:1.75, overflowX:'auto', margin:0,
        fontFamily:"'JetBrains Mono','Fira Code',monospace",
        border:'1px solid #1e293b', whiteSpace:'pre-wrap', wordBreak:'break-word' }}>
        <code>{code}</code>
      </pre>
      <button onClick={()=>{ navigator.clipboard?.writeText(code); setCopied(true); setTimeout(()=>setCopied(false),1500); }}
        style={{ position:'absolute', top:8, right:8, background:copied?'#22c55e':'#334155',
          color:'#fff', border:'none', borderRadius:4, padding:'3px 8px', fontSize:11, cursor:'pointer' }}>
        {copied ? '✓' : '⎘'}
      </button>
    </div>
  );
}

// ═══ BOUTON TÉLÉCHARGEMENT PYTHON ═══
function DownloadBtn({ filename, content }) {
  const dl = () => {
    const blob = new Blob([content], { type:'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = filename; a.click();
    URL.revokeObjectURL(url);
  };
  return (
    <button onClick={dl} style={{ background:'#1e3a5f', border:'1px solid #3b82f6', color:'#60a5fa',
      borderRadius:8, padding:'6px 14px', cursor:'pointer', fontSize:12, fontWeight:700,
      display:'flex', alignItems:'center', gap:6, transition:'all 0.2s',
      fontFamily:"'JetBrains Mono',monospace" }}
      onMouseEnter={e=>{e.currentTarget.style.background='#1d4ed8';e.currentTarget.style.color='#fff';}}
      onMouseLeave={e=>{e.currentTarget.style.background='#1e3a5f';e.currentTarget.style.color='#60a5fa';}}>
      ⬇ {filename}
    </button>
  );
}

// ═══ VISIONNEUSE PDF ÉNONCÉ (PDF.js) ═══
function PdfViewer({ sujetId }) {
  const [pages, setPages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [pdfBytes, setPdfBytes] = useState(null);

  useEffect(() => {
    setPages([]); setLoading(true); setError(null);
    const b64 = PDF_B64[sujetId];
    if (!b64) { setError('PDF non disponible'); setLoading(false); return; }
    try {
      const bin = atob(b64);
      const arr = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
      setPdfBytes(arr);
    } catch(e) { setError('Erreur décodage PDF'); setLoading(false); }
  }, [sujetId]);

  useEffect(() => {
    if (!pdfBytes) return;
    let cancelled = false;
    const render = async () => {
      try {
        if (!window.pdfjsLib) {
          await new Promise((res, rej) => {
            const s = document.createElement('script');
            s.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js';
            s.onload = res; s.onerror = rej;
            document.head.appendChild(s);
          });
          window.pdfjsLib.GlobalWorkerOptions.workerSrc =
            'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
        }
        const pdf = await window.pdfjsLib.getDocument({ data: pdfBytes }).promise;
        if (cancelled) return;
        const rendered = [];
        for (let p = 1; p <= pdf.numPages; p++) {
          const page = await pdf.getPage(p);
          const vp = page.getViewport({ scale: 1.5 });
          const canvas = document.createElement('canvas');
          canvas.width = vp.width; canvas.height = vp.height;
          await page.render({ canvasContext: canvas.getContext('2d'), viewport: vp }).promise;
          if (cancelled) return;
          rendered.push(canvas.toDataURL('image/jpeg', 0.92));
        }
        setPages(rendered);
      } catch(e) { if (!cancelled) setError('Erreur rendu PDF : ' + e.message); }
      finally { if (!cancelled) setLoading(false); }
    };
    render();
    return () => { cancelled = true; };
  }, [pdfBytes]);

  const download = () => {
    if (!pdfBytes) return;
    const blob = new Blob([pdfBytes], { type:'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `NSI_2026_Sujet_${String(sujetId).padStart(2,'0')}.pdf`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={{ borderRadius:12, overflow:'hidden', border:'1px solid #1e293b' }}>
      <div style={{ background:'#131f35', padding:'10px 16px', display:'flex', gap:10,
        alignItems:'center', justifyContent:'space-between', flexWrap:'wrap' }}>
        <span style={{ fontSize:13, color:'#94a3b8', fontWeight:600 }}>
          📄 Sujet n°{String(sujetId).padStart(2,'0')} — Baccalauréat NSI 2026
          {pages.length > 0 && <span style={{ color:'#64748b', fontWeight:400 }}> · {pages.length} page{pages.length>1?'s':''}</span>}
        </span>
        <button onClick={download} disabled={!pdfBytes}
          style={{ background:'#1e3a5f', border:'1px solid #3b82f6', color:'#60a5fa',
            borderRadius:8, padding:'6px 14px', cursor:'pointer', fontSize:12, fontWeight:700,
            display:'flex', alignItems:'center', gap:5, opacity:pdfBytes?1:0.5 }}>
          ⬇ Télécharger le PDF
        </button>
      </div>
      <div style={{ background:'#1a1a2e', maxHeight:'80vh', overflowY:'auto', padding:'16px',
        display:'flex', flexDirection:'column', gap:12 }}>
        {loading && (
          <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:300, gap:16 }}>
            <div style={{ width:48, height:48, border:'4px solid #334155', borderTop:'4px solid #4f46e5',
              borderRadius:'50%', animation:'spin 1s linear infinite' }}/>
            <span style={{ color:'#64748b', fontSize:13 }}>Chargement du PDF...</span>
            <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
          </div>
        )}
        {error && <div style={{ textAlign:'center', color:'#ef4444', padding:40 }}>⚠ {error}</div>}
        {pages.map((src, i) => (
          <img key={i} src={src} alt={`Page ${i+1}`}
            style={{ width:'100%', borderRadius:6, boxShadow:'0 4px 16px rgba(0,0,0,0.5)', display:'block' }}
          />
        ))}
      </div>
    </div>
  );
}

function PythonHighlight({ code }) {
  const highlight = (src) => {
    const tokens = [];
    const patterns = [
      { re: /(#[^\n]*)/, cls: 'comment' },
      { re: /("""[\s\S]*?"""|'''[\s\S]*?'''|"(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*')/, cls: 'string' },
      { re: /\b(def|class|return|if|elif|else|for|while|in|not|and|or|import|from|as|pass|break|continue|lambda|with|try|except|finally|raise|yield|global|nonlocal|del|assert)\b/, cls: 'keyword' },
      { re: /\b(True|False|None|self|cls)\b/, cls: 'builtin' },
      { re: /\b(print|len|range|int|float|str|list|dict|tuple|set|bool|type|isinstance|hasattr|getattr|setattr|enumerate|zip|map|filter|sorted|reversed|open|sum|min|max|abs|round)\b(?=\s*\()/, cls: 'builtin' },
      { re: /\b(\d+\.?\d*)\b/, cls: 'number' },
      { re: /([+\-*\/=<>!&|%^~@]+)/, cls: 'op' },
    ];
    const colors = {
      comment:'#6b7280', string:'#a3e635', keyword:'#818cf8',
      builtin:'#38bdf8', number:'#fb923c', op:'#e879f9', default:'#d1fae5',
    };
    const parts = src.split('\n').map((line, li) => {
      let remaining = line;
      const spans = [];
      while (remaining.length > 0) {
        let matched = false;
        for (const { re, cls } of patterns) {
          const m = re.exec(remaining);
          if (m && m.index === 0) {
            spans.push(<span key={spans.length} style={{color:colors[cls]}}>{m[0]}</span>);
            remaining = remaining.slice(m[0].length);
            matched = true;
            break;
          } else if (m && m.index > 0) {
            spans.push(<span key={spans.length} style={{color:colors.default}}>{remaining.slice(0,m.index)}</span>);
            spans.push(<span key={spans.length+1} style={{color:colors[cls]}}>{m[0]}</span>);
            remaining = remaining.slice(m.index + m[0].length);
            matched = true;
            break;
          }
        }
        if (!matched) {
          spans.push(<span key={spans.length} style={{color:colors.default}}>{remaining}</span>);
          remaining = '';
        }
      }
      return <div key={li} style={{display:'flex',minHeight:'1.4em'}}><span style={{color:'#374151',minWidth:32,textAlign:'right',paddingRight:12,userSelect:'none',fontSize:11,lineHeight:'1.65em',flexShrink:0}}>{li+1}</span><span style={{flex:1}}>{spans}</span></div>;
    });
    return parts;
  };
  return (
    <div style={{background:'#060c18',padding:'14px 0',overflowX:'auto',maxHeight:'420px',overflowY:'auto',fontFamily:"'JetBrains Mono','Fira Code',monospace",fontSize:12,lineHeight:1.65}}>
      {highlight(code)}
    </div>
  );
}

// ═══ CONSOLE PYTHON (éditeur avec coloration + téléchargement) ═══
function PythonConsole({ sujetId, fichiers, couleur }) {
  const firstFile = Object.entries(fichiers)[0];
  const [filename, setFilename] = useState(firstFile ? firstFile[0] : `sujet_${String(sujetId).padStart(2,'0')}.py`);
  const [code, setCode] = useState(firstFile ? firstFile[1] : `# Sujet ${sujetId} — Écrivez votre code ici\n\n`);
  const [output, setOutput] = useState([]);
  const [pyStatus, setPyStatus] = useState('idle'); // idle | loading | ready | running | error
  const [pyodide, setPyodide] = useState(null);
  const [editorTab, setEditorTab] = useState('edit');
  const textareaRef = useRef(null);
  const outputRef = useRef(null);

  // Load Pyodide on first render
  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      if (window._pyodide) { setPyodide(window._pyodide); setPyStatus('ready'); return; }
      setPyStatus('loading');
      try {
        if (!window.loadPyodide) {
          await new Promise((res, rej) => {
            const s = document.createElement('script');
            s.src = 'https://cdn.jsdelivr.net/pyodide/v0.26.4/full/pyodide.js';
            s.onload = res; s.onerror = () => rej(new Error('Impossible de charger Pyodide'));
            document.head.appendChild(s);
          });
        }
        const py = await window.loadPyodide({
          indexURL: 'https://cdn.jsdelivr.net/pyodide/v0.26.4/full/',
          stdout: (msg) => { if (!cancelled) setOutput(o => [...o, {type:'out', text:msg}]); },
          stderr: (msg) => { if (!cancelled) setOutput(o => [...o, {type:'err', text:msg}]); },
        });
        if (cancelled) return;
        window._pyodide = py;
        setPyodide(py);
        setPyStatus('ready');
      } catch(e) {
        if (!cancelled) { setPyStatus('error'); setOutput([{type:'sys', text:`❌ Erreur chargement : ${e.message}`}]); }
      }
    };
    load();
    return () => { cancelled = true; };
  }, []);

  useEffect(() => {
    if (outputRef.current) outputRef.current.scrollTop = outputRef.current.scrollHeight;
  }, [output]);

  const runCode = async () => {
    if (!pyodide || pyStatus !== 'ready') return;
    setPyStatus('running');
    setOutput(o => [...o, {type:'sep', text:`─── Exécution ${new Date().toLocaleTimeString()} ───`}]);
    try {
      // Redirect stdout/stderr
      await pyodide.runPythonAsync(`
import sys, io
_stdout_bak = sys.stdout
_stderr_bak = sys.stderr
sys.stdout = io.StringIO()
sys.stderr = io.StringIO()
      `);
      let result;
      try {
        result = await pyodide.runPythonAsync(code);
      } catch(e) {
        const stdout = await pyodide.runPythonAsync('sys.stdout.getvalue()');
        const stderr = await pyodide.runPythonAsync('sys.stderr.getvalue()');
        await pyodide.runPythonAsync('sys.stdout = _stdout_bak; sys.stderr = _stderr_bak');
        if (stdout) stdout.split('\n').filter(Boolean).forEach(l => setOutput(o=>[...o,{type:'out',text:l}]));
        setOutput(o=>[...o,{type:'err',text:e.message}]);
        setPyStatus('ready'); return;
      }
      const stdout = await pyodide.runPythonAsync('sys.stdout.getvalue()');
      const stderr = await pyodide.runPythonAsync('sys.stderr.getvalue()');
      await pyodide.runPythonAsync('sys.stdout = _stdout_bak; sys.stderr = _stderr_bak');
      if (stdout) stdout.trimEnd().split('\n').forEach(l => setOutput(o=>[...o,{type:'out',text:l}]));
      if (stderr) stderr.trimEnd().split('\n').filter(Boolean).forEach(l => setOutput(o=>[...o,{type:'err',text:l}]));
      if (result !== undefined && result !== null) {
        const repr = String(result);
        if (repr !== 'None') setOutput(o=>[...o,{type:'ret',text:'→ '+repr}]);
      }
      setOutput(o=>[...o,{type:'ok',text:'✓ Terminé'}]);
    } catch(e) {
      setOutput(o=>[...o,{type:'err',text:e.message}]);
    } finally { setPyStatus('ready'); }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const ta = textareaRef.current;
      const s = ta.selectionStart, end = ta.selectionEnd;
      const nc = code.slice(0,s) + '    ' + code.slice(end);
      setCode(nc);
      setTimeout(() => { ta.selectionStart = ta.selectionEnd = s+4; }, 0);
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') { e.preventDefault(); runCode(); }
  };

  const download = () => {
    const blob = new Blob([code], { type:'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href=url; a.download=filename; a.click();
    URL.revokeObjectURL(url);
  };

  const statusInfo = {
    idle:    { label:'● En attente', color:'#475569' },
    loading: { label:'⟳ Chargement Python...', color:'#f59e0b' },
    ready:   { label:'● Python prêt', color:'#22c55e' },
    running: { label:'▶ Exécution...', color:'#818cf8' },
    error:   { label:'✕ Erreur', color:'#ef4444' },
  }[pyStatus];

  return (
    <div style={{border:'1px solid #1e293b',borderRadius:12,overflow:'hidden',display:'flex',flexDirection:'column'}}>
      {/* ─── Barre d'outils ─── */}
      <div style={{background:'#131f35',padding:'8px 14px',display:'flex',gap:8,alignItems:'center',flexWrap:'wrap',borderBottom:'1px solid #1e293b'}}>
        <span style={{fontSize:11,fontWeight:700,color:statusInfo.color,minWidth:130}}>{statusInfo.label}</span>
        <input value={filename} onChange={e=>setFilename(e.target.value)}
          style={{background:'#0f172a',border:'1px solid #334155',color:'#60a5fa',borderRadius:6,padding:'3px 9px',fontSize:12,fontFamily:"'JetBrains Mono',monospace",fontWeight:700,minWidth:150,flex:1}}/>
        <div style={{display:'flex',gap:4,flexWrap:'wrap'}}>
          {Object.entries(fichiers).map(([fname,content])=>(
            <button key={fname} onClick={()=>{setFilename(fname);setCode(content);setEditorTab('edit');textareaRef.current?.focus();}}
              style={{background:'#1e3a5f',border:'1px solid #3b82f6',color:'#60a5fa',borderRadius:6,padding:'3px 9px',cursor:'pointer',fontSize:11,fontWeight:600}}>
              📂 {fname}
            </button>
          ))}
          <button onClick={()=>setCode(`# Sujet ${sujetId}\n\n`)}
            style={{background:'#1e293b',border:'1px solid #475569',color:'#94a3b8',borderRadius:6,padding:'3px 9px',cursor:'pointer',fontSize:11}}>🗒</button>
          <button onClick={download}
            style={{background:'#1e293b',border:'1px solid #334155',color:'#94a3b8',borderRadius:6,padding:'3px 9px',cursor:'pointer',fontSize:11,fontWeight:600}}>💾</button>
          <button onClick={runCode} disabled={pyStatus!=='ready'}
            style={{background:pyStatus==='ready'?'linear-gradient(135deg,#22c55e,#16a34a)':'#1e293b',
                    border:'none',color:pyStatus==='ready'?'#fff':'#475569',borderRadius:8,
                    padding:'4px 16px',cursor:pyStatus==='ready'?'pointer':'default',
                    fontSize:13,fontWeight:700,display:'flex',alignItems:'center',gap:6,transition:'all 0.2s'}}>
            {pyStatus==='running'?'⟳ ...' : pyStatus==='loading'?'⟳ Chargement' : '▶ Exécuter'}
            <span style={{fontSize:9,opacity:0.7}}>Ctrl+↵</span>
          </button>
        </div>
      </div>

      {/* ─── Sous-onglets éditeur ─── */}
      <div style={{background:'#0c1225',display:'flex',borderBottom:'1px solid #1e293b'}}>
        {[['edit','✏️ Code'],['preview','🎨 Coloré']].map(([id,lbl])=>(
          <button key={id} onClick={()=>setEditorTab(id)}
            style={{background:'none',border:'none',cursor:'pointer',padding:'6px 14px',fontSize:12,
                    color:editorTab===id?couleur:'#475569',
                    borderBottom:editorTab===id?`2px solid ${couleur}`:'2px solid transparent',
                    fontWeight:editorTab===id?700:400}}>
            {lbl}
          </button>
        ))}
        <span style={{marginLeft:'auto',padding:'6px 14px',fontSize:11,color:'#374151'}}>
          {code.split('\n').length}L
        </span>
      </div>

      {/* ─── Éditeur ─── */}
      {editorTab==='edit' && (
        <div style={{display:'flex',background:'#060c18',minHeight:'35vh',maxHeight:'45vh',overflow:'hidden'}}>
          {/* Numéros de lignes */}
          <div style={{background:'#0a0f1a',padding:'14px 0',minWidth:38,overflowY:'hidden',flexShrink:0,borderRight:'1px solid #1e293b'}}>
            {code.split('\n').map((_,i)=>(
              <div key={i} style={{textAlign:'right',paddingRight:8,paddingLeft:4,color:'#334155',fontSize:12,lineHeight:'1.65em',fontFamily:"'JetBrains Mono',monospace",userSelect:'none'}}>{i+1}</div>
            ))}
          </div>
          <textarea ref={textareaRef} value={code} onChange={e=>setCode(e.target.value)}
            onKeyDown={handleKeyDown} spellCheck={false}
            style={{flex:1,background:'#060c18',color:'#e2e8f0',border:'none',outline:'none',
                    padding:'14px 14px',fontSize:12,lineHeight:'1.65em',
                    fontFamily:"'JetBrains Mono','Fira Code',monospace",
                    resize:'none',whiteSpace:'pre',overflowX:'auto',overflowY:'auto',caretColor:'#818cf8'}}/>
        </div>
      )}
      {editorTab==='preview' && (
        <div style={{minHeight:'35vh',maxHeight:'45vh',overflowY:'auto'}}>
          <PythonHighlight code={code}/>
        </div>
      )}

      {/* ─── Terminal output ─── */}
      <div style={{background:'#020408',borderTop:'2px solid #1e293b'}}>
        <div style={{background:'#0a0f1a',padding:'5px 14px',display:'flex',justifyContent:'space-between',alignItems:'center',borderBottom:'1px solid #1e293b'}}>
          <span style={{fontSize:11,color:'#4b5563',fontFamily:"'JetBrains Mono',monospace"}}>SORTIE</span>
          <button onClick={()=>setOutput([])}
            style={{background:'none',border:'none',color:'#374151',cursor:'pointer',fontSize:11,padding:'2px 8px',borderRadius:4}}
            onMouseEnter={e=>e.currentTarget.style.color='#94a3b8'} onMouseLeave={e=>e.currentTarget.style.color='#374151'}>
            ✕ Effacer
          </button>
        </div>
        <div ref={outputRef} style={{minHeight:120,maxHeight:'30vh',overflowY:'auto',padding:'12px 16px',fontFamily:"'JetBrains Mono','Fira Code',monospace",fontSize:12,lineHeight:1.6}}>
          {output.length===0 && (
            <span style={{color:'#374151'}}>
              {pyStatus==='loading' ? '⟳ Chargement de Python (Pyodide)... ~5 secondes la première fois...' :
               pyStatus==='ready'  ? '● Python prêt — cliquez ▶ Exécuter ou Ctrl+Entrée' :
               '● Console Python — exécution réelle dans le navigateur'}
            </span>
          )}
          {output.map((line,i) => (
            <div key={i} style={{color:
              line.type==='err' ? '#f87171' :
              line.type==='ret' ? '#818cf8' :
              line.type==='ok'  ? '#22c55e' :
              line.type==='sep' ? '#374151' :
              line.type==='sys' ? '#f59e0b' :
              '#d1fae5', paddingLeft: line.type==='sep'?0:2, borderTop: line.type==='sep'?'1px dashed #1e293b':undefined, marginTop:line.type==='sep'?4:undefined, paddingTop:line.type==='sep'?4:undefined}}>
              {line.text}
            </div>
          ))}
          {pyStatus==='running' && (
            <div style={{color:'#818cf8',marginTop:4}}>
              <span style={{animation:'blink 1s linear infinite'}}>▌</span>
              <style>{`@keyframes blink{0%,100%{opacity:1}50%{opacity:0}}`}</style>
            </div>
          )}
        </div>
      </div>

      {/* ─── Barre de statut ─── */}
      <div style={{background:'#0a0f1a',padding:'5px 14px',display:'flex',justifyContent:'space-between',alignItems:'center',borderTop:'1px solid #1e293b'}}>
        <span style={{fontSize:10,color:'#374151'}}>Python 3 (Pyodide WebAssembly) · Tab=4esp · Ctrl+Entrée=Exécuter</span>
        <button onClick={download} style={{background:`${couleur}20`,border:`1px solid ${couleur}50`,color:couleur,borderRadius:5,padding:'3px 10px',cursor:'pointer',fontSize:10,fontWeight:700}}>
          ⬇ {filename}
        </button>
      </div>
    </div>
  );
}

// ═══ VISIONNEUSE CORRECTION PDF (ECEBac / kxs.fr) ═══
function CorrectionPdfViewer({ sujetId }) {
  const [pages, setPages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [tried, setTried] = useState(false);

  const pdfUrl = CORR_PDF_URLS[sujetId];
  const ecebacUrl = `https://ecebac.fr/sujet/${ECEBAC_IDS[sujetId]}`;

  const loadPdf = async () => {
    if (!pdfUrl) { setError('Correction PDF non disponible pour ce sujet.'); setTried(true); return; }
    setLoading(true); setError(null); setTried(true); setPages([]);
    try {
      if (!window.pdfjsLib) {
        await new Promise((res, rej) => {
          const s = document.createElement('script');
          s.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js';
          s.onload = res; s.onerror = rej;
          document.head.appendChild(s);
        });
        window.pdfjsLib.GlobalWorkerOptions.workerSrc =
          'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
      }
      const resp = await fetch(pdfUrl);
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const arrBuf = await resp.arrayBuffer();
      const pdf = await window.pdfjsLib.getDocument({ data: new Uint8Array(arrBuf) }).promise;
      const rendered = [];
      for (let p = 1; p <= pdf.numPages; p++) {
        const page = await pdf.getPage(p);
        const vp = page.getViewport({ scale: 1.5 });
        const canvas = document.createElement('canvas');
        canvas.width = vp.width; canvas.height = vp.height;
        const ctx = canvas.getContext('2d');
        await page.render({ canvasContext: ctx, viewport: vp }).promise;
        rendered.push(canvas.toDataURL('image/jpeg', 0.92));
      }
      setPages(rendered);
    } catch(e) {
      setError(`Impossible de charger le PDF : ${e.message}. Consultez directement ECEBac.`);
    } finally { setLoading(false); }
  };

  return (
    <div style={{borderRadius:12,overflow:'hidden',border:'1px solid #1e293b'}}>
      <div style={{background:'#131f35',padding:'12px 16px',display:'flex',gap:10,alignItems:'center',flexWrap:'wrap',borderBottom:'1px solid #1e293b'}}>
        <span style={{fontSize:13,color:'#94a3b8',fontWeight:600}}>
          📑 Correction officielle — Sujet {String(sujetId).padStart(2,'0')}
        </span>
        <div style={{display:'flex',gap:8,marginLeft:'auto',flexWrap:'wrap'}}>
          <a href={ecebacUrl} target="_blank" rel="noreferrer"
            style={{background:'#1e3a5f',border:'1px solid #3b82f6',color:'#60a5fa',borderRadius:8,padding:'6px 12px',textDecoration:'none',fontSize:12,fontWeight:700}}>
            🔗 Voir sur ECEBac
          </a>
          {pdfUrl && (
            <a href={pdfUrl} target="_blank" rel="noreferrer" download
              style={{background:'#1e293b',border:'1px solid #475569',color:'#94a3b8',borderRadius:8,padding:'6px 12px',textDecoration:'none',fontSize:12,fontWeight:600}}>
              ⬇ PDF direct
            </a>
          )}
          {!tried && (
            <button onClick={loadPdf}
              style={{background:'linear-gradient(135deg,#059669,#047857)',border:'none',color:'#fff',borderRadius:8,padding:'6px 14px',cursor:'pointer',fontSize:12,fontWeight:700}}>
              🚀 Charger la correction
            </button>
          )}
        </div>
      </div>
      <div style={{background:'#0a0f1a',padding:'24px',minHeight:200}}>
        {!tried && (
          <div style={{textAlign:'center',padding:'40px 20px'}}>
            <div style={{fontSize:48,marginBottom:12}}>📑</div>
            <p style={{color:'#64748b',fontSize:14,marginBottom:20,lineHeight:1.6}}>
              Correction disponible via <strong style={{color:'#60a5fa'}}>ECEBac.fr</strong> (Thomas Beline / kxs.fr).<br/>
              Cliquez pour charger le PDF directement ici, ou visitez ECEBac pour d'autres corrections (vidéo, Gilles Lassus...).
            </p>
            <button onClick={loadPdf}
              style={{background:'linear-gradient(135deg,#059669,#047857)',border:'none',color:'#fff',borderRadius:10,padding:'12px 28px',cursor:'pointer',fontSize:14,fontWeight:700,boxShadow:'0 8px 24px rgba(5,150,105,0.3)'}}>
              🚀 Charger la correction PDF
            </button>
          </div>
        )}
        {loading && (
          <div style={{display:'flex',flexDirection:'column',alignItems:'center',gap:16,padding:40}}>
            <div style={{width:48,height:48,border:'4px solid #334155',borderTop:'4px solid #059669',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
            <span style={{color:'#64748b',fontSize:13}}>Chargement de la correction...</span>
          </div>
        )}
        {error && (
          <div style={{textAlign:'center',padding:24}}>
            <div style={{color:'#f59e0b',fontSize:13,marginBottom:12}}>⚠ {error}</div>
            <a href={ecebacUrl} target="_blank" rel="noreferrer"
              style={{display:'inline-block',background:'#1e3a5f',border:'1px solid #3b82f6',color:'#60a5fa',borderRadius:8,padding:'8px 18px',textDecoration:'none',fontSize:13,fontWeight:700}}>
              Voir les corrections sur ECEBac →
            </a>
          </div>
        )}
        {pages.map((src,i)=>(
          <img key={i} src={src} alt={`Correction page ${i+1}`}
            style={{width:'100%',borderRadius:6,boxShadow:'0 4px 16px rgba(0,0,0,0.5)',display:'block',marginBottom:12}}
          />
        ))}
      </div>
    </div>
  );
}

// ═══ CHATBOT M. MORANDINO ═══
function Chatbot({ onClose, currentSubjectId }) {
  const [messages, setMessages] = useState([
    { role:'assistant', content:"Bien le bonjour ! Je suis **M. Morandino**, votre professeur de NSI.\n\nJe suis à votre entière disposition pour vous aider à réviser les **23 sujets** de l'épreuve pratique 2026. Posez-moi vos questions : Python, algorithmes, POO, SQL, binaire...\n\nReconcentrez-vous sur la NSI, et c'est parti ! 📐" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:'smooth' }); }, [messages]);

  const buildSystem = (currentSubjectId) => {
    const subjectContext = currentSubjectId ? (() => {
      const meta = META[currentSubjectId];
      const corrs = CORRECTIONS[currentSubjectId] || [];
      const enonce = ENONCES[currentSubjectId] || '';
      const corrsSummary = corrs.map((q,i) => `${q.q}\n${q.explication||q.r||''}\n${q.code?'Code:\n'+q.code:''}`).join('\n\n---\n\n');
      return `\n\n== CONTEXTE ACTUEL : Sujet ${currentSubjectId} — "${meta?.titre}" ==\n\nÉnoncé complet :\n${enonce.slice(0,3000)}${enonce.length>3000?'\n[... énoncé tronqué ...]':''}\n\nCorrections complètes :\n${corrsSummary}`;
    })() : '';

    return `Tu es M. Morandino, professeur de NSI en Terminale générale. Passionné, exigeant, pédagogue, avec un caractère bien trempé.

EXPRESSIONS IDIOMATIQUES :
- "Non mais STOP." / "Reconcentrez-vous sur la NSI !" : quand hors-sujet
- "Non mais arrêtez..." : pour les erreurs classiques (avec affection désespérée)
- "Non mais... Lenny Arnoult !" : pour les erreurs évidentes
- "Vous parlez, vous sortez." : rhétoriquement pour insister sur la concentration
- "Voilà ! EXACTEMENT ce que j'attendais !" : pour féliciter

RÈGLES ABSOLUES :
- Vouvoiement SYSTÉMATIQUE toujours, sans exception
- Langage soutenu, châtié mais chaleureux
- Mots en MAJUSCULES pour l'emphase pédagogique (FONDAMENTAL, JAMAIS, TOUJOURS)
- Interpellations : "Vous me suivez ?", "C'est limpide ?", "N'est-ce pas ?"

CONNAISSANCE DES 23 SUJETS NSI 2026 :
Tu as accès aux énoncés complets et aux corrections détaillées de tous les sujets. Quand on te pose une question sur un sujet, tu t'appuies sur le contenu réel du sujet (énoncé, questions, fonctions à compléter, bugs à corriger).

Les 23 sujets : S1-RLE images, S2-Salaires kNN, S3-Cycle menstruel, S4-Plantes POO, S5-Empreinte carbone JSON, S6-Smoothies, S7-Coccinelles simulation, S8-Flottants BCD, S9-Modélisation 3D, S10-Compteurs eau, S11-Renards kNN, S12-Refuge renards CSV, S13-Ballon sonde, S14-Evacuation bâtiment, S15-Cabinet vétérinaire SQL, S16-Warming stripes, S17-Handball budget, S18-Températures Polynésie, S19-Réservoirs Polynésie, S20-Empreinte numérique, S21-Flashcards Leitner, S22-QR Codes, S23-Capteurs DEMETER.

Tu réponds en français uniquement. Tu es M. Morandino, pas un assistant IA.${subjectContext}`;
  };

  const renderMsg = (content) => content.split(/(```[\s\S]*?```)/g).map((part,i) => {
    if (part.startsWith('```')) {
      const code = part.replace(/^```\w*\n?/,'').replace(/```$/,'');
      return <CodeBlock key={i} code={code}/>;
    }
    return <span key={i}>{part.split(/(\*\*[^*]+\*\*|`[^`]+`)/g).map((t,j) => {
      if (t.startsWith('**')&&t.endsWith('**')) return <strong key={j}>{t.slice(2,-2)}</strong>;
      if (t.startsWith('`')&&t.endsWith('`')) return <code key={j} style={{background:'#1e293b',color:'#93c5fd',padding:'1px 5px',borderRadius:3,fontSize:12,fontFamily:'monospace'}}>{t.slice(1,-1)}</code>;
      return t;
    })}</span>;
  });

const send = async () => {
  const text = input.trim();
  if (!text || loading) return;
  const newMsgs = [...messages, { role:'user', content:text }];
  setMessages(newMsgs); setInput(''); setLoading(true);
  try {
    const res = await fetch('/api/chat', {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        system: buildSystem(currentSubjectId),
        messages: newMsgs.map(m=>({role:m.role, content:m.content}))
      })
    });
    const data = await res.json();
    const reply = data.choices?.[0]?.message?.content || "Je n'ai pas pu répondre.";
    setMessages(prev=>[...prev,{role:'assistant',content:reply}]);
  } catch {
    setMessages(prev=>[...prev,{role:'assistant',content:"Erreur réseau. Réessayez !"}]);
  }
  setLoading(false);
};

  const sugg = ['Expliquez le codage RLE','Qu est-ce que le k-NN ?','Bug du remove() sujet 4','Aide SQL sujet 15','Flottants et BCD sujet 8'];

  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.85)',zIndex:9998,display:'flex',alignItems:'flex-end',justifyContent:'flex-end',padding:20}}>
      <div style={{background:'#0a0f1a',border:'1px solid #334155',borderRadius:20,width:'min(480px,100%)',height:'min(680px,90vh)',display:'flex',flexDirection:'column',boxShadow:'0 32px 96px rgba(0,0,0,0.9)',overflow:'hidden'}}>
        <div style={{background:'linear-gradient(135deg,#1e1b4b,#0c1445)',padding:'16px 20px',display:'flex',alignItems:'center',gap:12}}>
          <div style={{width:46,height:46,background:'linear-gradient(135deg,#6366f1,#4f46e5)',borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',fontSize:22,flexShrink:0}}>👨‍🏫</div>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,color:'#f1f5f9',fontSize:16}}>M. Morandino</div>
            <div style={{fontSize:12,color:'#818cf8',fontStyle:'italic'}}>"Reconcentrez-vous sur la NSI !"</div>
          </div>
          <button onClick={onClose} style={{background:'#1e293b',border:'none',color:'#94a3b8',borderRadius:8,padding:'6px 10px',cursor:'pointer',fontSize:16}}>✕</button>
        </div>
        <div style={{flex:1,overflowY:'auto',padding:16,display:'flex',flexDirection:'column',gap:12}}>
          {messages.map((m,i) => (
            <div key={i} style={{display:'flex',gap:10,alignItems:'flex-start',flexDirection:m.role==='user'?'row-reverse':'row'}}>
              {m.role==='assistant' && <div style={{width:32,height:32,background:'linear-gradient(135deg,#6366f1,#4f46e5)',borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',fontSize:16,flexShrink:0,marginTop:2}}>👨‍🏫</div>}
              <div style={{background:m.role==='user'?'#4f46e5':'#111827',border:m.role==='user'?'none':'1px solid #1e293b',borderRadius:m.role==='user'?'18px 18px 4px 18px':'18px 18px 18px 4px',padding:'12px 16px',maxWidth:'82%',color:m.role==='user'?'#fff':'#cbd5e1',fontSize:14,lineHeight:1.65}}>
                {renderMsg(m.content)}
              </div>
            </div>
          ))}
          {loading && <div style={{display:'flex',gap:10,alignItems:'center'}}>
            <div style={{width:32,height:32,background:'linear-gradient(135deg,#6366f1,#4f46e5)',borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',fontSize:16}}>👨‍🏫</div>
            <div style={{background:'#111827',border:'1px solid #1e293b',borderRadius:'18px 18px 18px 4px',padding:'12px 16px'}}><span style={{color:'#6366f1',fontSize:20,letterSpacing:4}}>•••</span></div>
          </div>}
          <div ref={bottomRef}/>
        </div>
        {messages.length <= 1 && <div style={{padding:'0 16px 8px',display:'flex',flexWrap:'wrap',gap:6}}>
          {sugg.map((s,i) => <button key={i} onClick={()=>setInput(s)} style={{background:'#1e293b',border:'1px solid #334155',color:'#94a3b8',borderRadius:20,padding:'5px 12px',cursor:'pointer',fontSize:12,whiteSpace:'nowrap'}}>{s}</button>)}
        </div>}
        <div style={{padding:'12px 16px',borderTop:'1px solid #1e293b',display:'flex',gap:8}}>
          <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&!e.shiftKey&&send()}
            placeholder="Votre question, je vous en prie..."
            style={{flex:1,background:'#1e293b',border:'1px solid #334155',borderRadius:12,padding:'10px 14px',color:'#f1f5f9',fontSize:13,outline:'none'}}/>
          <button onClick={send} disabled={loading||!input.trim()}
            style={{background:loading||!input.trim()?'#1e293b':'#4f46e5',border:'none',borderRadius:12,padding:'10px 16px',cursor:loading||!input.trim()?'default':'pointer',color:'#fff',fontSize:16}}>➤</button>
        </div>
      </div>
    </div>
  );
}

// ═══ COMPOSANT PRINCIPAL ═══
